53	// GetBeadSnapshots implements ddxgraphql.StateProvider.
54	//
55	// When projectID is non-empty this delegates to GetBeadSnapshotsForProject so
56	// the resolver path opens exactly one project's store; a scoped query never
57	// pays the N-project scan cost (ddx-9ce6842a Part 2 step 1). When projectID is
58	// empty every registered project is scanned — that is still O(projects) by
59	// necessity, but each project's bead.Store receives a pushed-down filter so
60	// non-matching beads are never materialized as BeadSnapshot values.
61	func (s *ServerState) GetBeadSnapshots(status, label, projectID, search string) []ddxgraphql.BeadSnapshot {
62		if projectID != "" {
63			return s.GetBeadSnapshotsForProject(projectID, status, label, search)
64		}
65		projects := s.GetProjects()
66		pred := beadFilterPredicate(status, label, search)
67		var result []ddxgraphql.BeadSnapshot
68		for _, proj := range projects {
69			result = append(result, s.beadSnapshotsForProjectEntry(proj, pred)...)
70		}
71		return result
72	}
73	
74	// GetBeadSnapshotsForProject implements ddxgraphql.StateProvider. It opens
75	// exactly one project's bead store — iteration over other projects is not
76	// performed for any reason, so the cross-project loop cost is avoided for the
77	// common per-project bead list.
78	func (s *ServerState) GetBeadSnapshotsForProject(projectID, status, label, search string) []ddxgraphql.BeadSnapshot {
79		if projectID == "" {
80			return nil
81		}
82		proj, ok := s.GetProjectByID(projectID)
83		if !ok {
84			return nil
85		}
86		pred := beadFilterPredicate(status, label, search)
87		return s.beadSnapshotsForProjectEntry(proj, pred)
88	}
89	
90	// beadStoreOpenHook is a test-only hook: when non-nil, every call to
91	// beadSnapshotsForProjectEntry invokes it with the project path it is about
92	// to open. Tests use this to assert that the scoped path opens exactly one
93	// project's store (ddx-9ce6842a AC §3).
94	var beadStoreOpenHook func(projectPath string)
95	
96	// beadSnapshotsForProjectEntry reads the single project's bead store, applies
97	// the (possibly nil) predicate at the store layer (filter pushdown), and
98	// returns GraphQL snapshots for the matching beads. Callers are responsible
99	// for deciding which projects to pass through — this helper never touches any
100	// other project's state.
101	func (s *ServerState) beadSnapshotsForProjectEntry(proj ProjectEntry, pred func(bead.Bead) bool) []ddxgraphql.BeadSnapshot {
102		if beadStoreOpenHook != nil {
103			beadStoreOpenHook(proj.Path)
104		}
105		store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
106		beads, err := store.ReadAllFiltered(pred)
107		if err != nil {
108			return nil
109		}
110		out := make([]ddxgraphql.BeadSnapshot, 0, len(beads))
111		for _, b := range beads {
112			s.rememberBeadLocation(b.ID, proj)
113			out = append(out, beadSnapshotFromStoreBead(proj.ID, b))
114		}
115		return out
116	}
