176	func (s *ServerState) lookupBeadLocation(id string) (beadIndexEntry, bool) {
177		s.beadIndexMu.RLock()
178		defer s.beadIndexMu.RUnlock()
179		if s.beadIndex == nil {
180			return beadIndexEntry{}, false
181		}
182		loc, ok := s.beadIndex[id]
183		return loc, ok
184	}
