192	func readBeadSnapshotFromProject(proj ProjectEntry, id string) (*ddxgraphql.BeadSnapshot, bool) {
193		store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
194		b, err := store.Get(id)
195		if err != nil {
196			return nil, false
197		}
198		snap := beadSnapshotFromStoreBead(proj.ID, *b)
199		return &snap, true
200	}
