202	func beadSnapshotFromStoreBead(projectID string, b bead.Bead) ddxgraphql.BeadSnapshot {
203		snap := ddxgraphql.BeadSnapshot{
204			ProjectID:   projectID,
205			ID:          b.ID,
206			Title:       b.Title,
207			Status:      b.Status,
208			Priority:    b.Priority,
209			IssueType:   b.IssueType,
210			Owner:       b.Owner,
211			CreatedAt:   b.CreatedAt,
212			CreatedBy:   b.CreatedBy,
213			UpdatedAt:   b.UpdatedAt,
214			Labels:      b.Labels,
215			Parent:      b.Parent,
216			Description: b.Description,
217			Acceptance:  b.Acceptance,
218			Notes:       b.Notes,
219		}
220		for _, d := range b.Dependencies {
221			snap.Dependencies = append(snap.Dependencies, ddxgraphql.BeadDependencySnapshot{
222				IssueID:     d.IssueID,
223				DependsOnID: d.DependsOnID,
224				Type:        d.Type,
225				CreatedAt:   d.CreatedAt,
226				CreatedBy:   d.CreatedBy,
227				Metadata:    d.Metadata,
228			})
229		}
230		return snap
231	}
