233	func projectEntryToGQL(e ProjectEntry) *ddxgraphql.Project {
234		p := &ddxgraphql.Project{
235			ID:           e.ID,
236			Name:         e.Name,
237			Path:         e.Path,
238			RegisteredAt: e.RegisteredAt.UTC().Format(time.RFC3339),
239			LastSeen:     e.LastSeen.UTC().Format(time.RFC3339),
240		}
241		if e.GitRemote != "" {
242			p.GitRemote = &e.GitRemote
243		}
244		if e.Unreachable {
245			b := true
246			p.Unreachable = &b
247		}
248		if e.TombstonedAt != nil {
249			ts := e.TombstonedAt.UTC().Format(time.RFC3339)
250			p.TombstonedAt = &ts
251		}
252		return p
253	}
