257	// GetWorkersGraphQL implements ddxgraphql.StateProvider.
258	// Reads worker records from disk and returns them as GraphQL Worker values.
259	// If projectID is non-empty, only workers for that project root are returned.
260	func (s *ServerState) GetWorkersGraphQL(projectID string) []*ddxgraphql.Worker {
261		if s.workingDir == "" {
262			return nil
263		}
264		workersDir := filepath.Join(s.workingDir, ".ddx", "workers")
265		entries, err := os.ReadDir(workersDir)
266		if err != nil {
267			return nil
268		}
269		var out []*ddxgraphql.Worker
270		for _, entry := range entries {
271			if !entry.IsDir() {
272				continue
273			}
274			data, err := os.ReadFile(filepath.Join(workersDir, entry.Name(), "status.json"))
275			if err != nil {
276				continue
277			}
278			var rec WorkerRecord
279			if err := json.Unmarshal(data, &rec); err != nil {
280				continue
281			}
282			if projectID != "" && rec.ProjectRoot != projectID {
283				continue
284			}
285			out = append(out, workerFromRecord(rec))
286		}
287		// Newest first.
288		sort.Slice(out, func(i, j int) bool {
289			si, sj := out[i].StartedAt, out[j].StartedAt
290			if si == nil || sj == nil {
291				return si != nil
292			}
293			ti, _ := time.Parse(time.RFC3339, *si)
294			tj, _ := time.Parse(time.RFC3339, *sj)
295			return ti.After(tj)
296		})
297		return out
298	}
