317	func (s *ServerState) GetWorkerLogGraphQL(id string) *ddxgraphql.WorkerLog {
318		if s.workingDir == "" {
319			return &ddxgraphql.WorkerLog{}
320		}
321		// Read the worker record to find the log path.
322		data, err := os.ReadFile(filepath.Join(s.workingDir, ".ddx", "workers", id, "status.json"))
323		if err != nil {
324			return &ddxgraphql.WorkerLog{}
325		}
326		var rec WorkerRecord
327		if err := json.Unmarshal(data, &rec); err != nil {
328			return &ddxgraphql.WorkerLog{}
329		}
330		stdout := ""
331		if rec.StdoutPath != "" {
332			logPath := rec.StdoutPath
333			if !filepath.IsAbs(logPath) {
334				logPath = filepath.Join(s.workingDir, logPath)
335			}
336			if raw, err := os.ReadFile(logPath); err == nil {
337				stdout = string(raw)
338			}
339		}
340		return &ddxgraphql.WorkerLog{Stdout: stdout, Stderr: ""}
341	}
