379	// workerFromRecord converts a WorkerRecord to the GraphQL Worker type.
380	func workerFromRecord(rec WorkerRecord) *ddxgraphql.Worker {
381		attempts := rec.Attempts
382		successes := rec.Successes
383		failures := rec.Failures
384		w := &ddxgraphql.Worker{
385			ID:           rec.ID,
386			Kind:         rec.Kind,
387			State:        rec.State,
388			ProjectRoot:  rec.ProjectRoot,
389			Attempts:     &attempts,
390			Successes:    &successes,
391			Failures:     &failures,
392			RecentEvents: []*ddxgraphql.WorkerRecentEvent{},
393		}
394		if rec.Status != "" {
395			w.Status = &rec.Status
396		}
397		if rec.Harness != "" {
398			w.Harness = &rec.Harness
399		}
400		if rec.Provider != "" {
401			w.Provider = &rec.Provider
402		}
403		if rec.Model != "" {
404			w.Model = &rec.Model
405		}
406		if rec.Effort != "" {
407			w.Effort = &rec.Effort
408		}
409		if rec.Once {
410			b := true
411			w.Once = &b
412		}
413		if rec.PollInterval != "" {
414			w.PollInterval = &rec.PollInterval
415		}
416		if !rec.StartedAt.IsZero() {
417			s := rec.StartedAt.UTC().Format(time.RFC3339)
418			w.StartedAt = &s
419		}
420		if !rec.FinishedAt.IsZero() {
421			s := rec.FinishedAt.UTC().Format(time.RFC3339)
422			w.FinishedAt = &s
423		}
424		if rec.Error != "" {
425			w.Error = &rec.Error
426		}
427		if rec.StdoutPath != "" {
428			w.StdoutPath = &rec.StdoutPath
429		}
430		if rec.SpecPath != "" {
431			w.SpecPath = &rec.SpecPath
432		}
433		if rec.CurrentBead != "" {
434			w.CurrentBead = &rec.CurrentBead
435		}
436		if rec.LastError != "" {
437			w.LastError = &rec.LastError
438		}
439		if rec.LastResult != nil {
440			w.LastResult = workerResultFromRecord(rec.LastResult)
441		}
442		if rec.CurrentAttempt != nil {
443			w.CurrentAttempt = currentAttemptFromRecord(rec.CurrentAttempt)
444		}
445		for _, p := range rec.RecentPhases {
446			pt := p // copy
447			w.RecentPhases = append(w.RecentPhases, &ddxgraphql.PhaseTransition{
448				Phase:    pt.Phase,
449				Ts:       pt.TS.UTC().Format(time.RFC3339),
450				PhaseSeq: pt.PhaseSeq,
451			})
452		}
453		if rec.LastAttempt != nil {
454			w.LastAttempt = lastAttemptFromRecord(rec.LastAttempt)
455		}
456		if rec.LandSummary != nil {
457			w.LandSummary = landSummaryFromRecord(rec.LandSummary)
458		}
459		return w
460	}
