600	// GetAgentSessionsGraphQL implements ddxgraphql.StateProvider.
601	// Reads pointer-only monthly session shards from every registered project.
602	func (s *ServerState) GetAgentSessionsGraphQL(startedAfter, startedBefore *time.Time) []*ddxgraphql.AgentSession {
603		projects := s.GetProjects(false)
604		var out []*ddxgraphql.AgentSession
605		for _, proj := range projects {
606			sessions := readProjectSessions(proj, startedAfter, startedBefore)
607			out = append(out, sessions...)
608		}
609		// Newest first.
610		sort.Slice(out, func(i, j int) bool {
611			ti, _ := time.Parse(time.RFC3339, out[i].StartedAt)
612			tj, _ := time.Parse(time.RFC3339, out[j].StartedAt)
613			return ti.After(tj)
614		})
615		return out
616	}
