618	// GetAgentSessionGraphQL implements ddxgraphql.StateProvider.
619	func (s *ServerState) GetAgentSessionGraphQL(id string) (*ddxgraphql.AgentSession, bool) {
620		projects := s.GetProjects(false)
621		for _, proj := range projects {
