151	func workerConnectionFrom(workers []*Worker, first *int, after *string, last *int, before *string) *WorkerConnection {
152		all := make([]*WorkerEdge, len(workers))
153		ids := make([]string, len(workers))
154		for i, w := range workers {
155			all[i] = &WorkerEdge{Node: w, Cursor: encodeStableCursor(w.ID)}
156			ids[i] = w.ID
157		}
158		startIdx, endIdx := stablePageBounds(ids, after, before)
159		slice := all[startIdx:endIdx]
160		truncByFirst, truncByLast := false, false
161		if first != nil && *first >= 0 && *first < len(slice) {
162			slice = slice[:*first]
163			truncByFirst = true
164		}
165		if last != nil && *last >= 0 && *last < len(slice) {
166			slice = slice[len(slice)-*last:]
167			truncByLast = true
168		}
169		pageInfo := &PageInfo{
170			HasPreviousPage: startIdx > 0 || truncByLast,
171			HasNextPage:     endIdx < len(all) || truncByFirst,
172		}
173		if len(slice) > 0 {
174			pageInfo.StartCursor = &slice[0].Cursor
175			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
176		}
177		return &WorkerConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
178	}
